create extension if not exists vector;
create table if not exists public.memory_capture_candidates (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text not null check(namespace in ('real_life','au')), source text not null, source_ref text, raw_excerpt text, redacted_excerpt text, memory_type text, title text, summary text, importance integer check(importance between 1 and 10), sensitivity text, confidence numeric, should_capture boolean, requires_review boolean, status text default 'pending' check(status in ('pending','approved','rejected','captured','blocked_secret','duplicate')), reason text, people jsonb default '[]', projects jsonb default '[]', risks jsonb default '[]', tags jsonb default '[]', metadata jsonb default '{}', created_at timestamptz default now(), reviewed_at timestamptz, captured_event_id uuid);
create table if not exists public.memory_profiles (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text not null check(namespace in ('real_life','au')), profile_type text not null, subject_key text not null, title text, summary text, facts jsonb default '[]', preferences jsonb default '[]', patterns jsonb default '[]', risks jsonb default '[]', open_loops jsonb default '[]', decisions jsonb default '[]', evidence_refs jsonb default '[]', confidence numeric, status text default 'active', version integer default 1, created_at timestamptz default now(), updated_at timestamptz default now());
create unique index if not exists memory_profiles_active_unique on public.memory_profiles(user_id, namespace, profile_type, subject_key, status) where status='active';
create table if not exists public.memory_embeddings (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text not null check(namespace in ('real_life','au')), source_table text not null, source_id uuid not null, memory_type text, content_hash text not null, embedding vector(1536), embedding_model text not null, embedding_dimensions integer not null default 1536, importance integer, sensitivity text, metadata jsonb default '{}', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.memory_session_digests (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text not null check(namespace in ('real_life','au')), source text not null, source_ref text, title text, summary text, durable_updates jsonb default '[]', decisions jsonb default '[]', open_loops jsonb default '[]', risks jsonb default '[]', people jsonb default '[]', projects jsonb default '[]', style_updates jsonb default '[]', candidate_ids jsonb default '[]', captured_event_ids jsonb default '[]', profile_ids jsonb default '[]', created_at timestamptz default now());
create table if not exists public.memory_open_loops (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text not null check(namespace in ('real_life','au')), loop_type text not null, subject_key text not null, title text, description text, severity integer, status text default 'open' check(status in ('open','acknowledged','resolved','deferred')), evidence_refs jsonb default '[]', next_action text, created_at timestamptz default now(), updated_at timestamptz default now(), resolved_at timestamptz);
create table if not exists public.memory_retrieval_logs (id uuid primary key default gen_random_uuid(), user_id uuid not null, namespace text, query_hash text, metadata jsonb default '{}', created_at timestamptz default now());
create table if not exists public.memory_model_call_logs (id uuid primary key default gen_random_uuid(), user_id uuid, namespace text, provider text, model text, task text, input_char_count integer, redacted boolean default true, metadata jsonb default '{}', created_at timestamptz default now());
create index if not exists memory_capture_candidates_user_ns_idx on public.memory_capture_candidates(user_id, namespace, created_at desc);
create index if not exists memory_profiles_user_ns_idx on public.memory_profiles(user_id, namespace, profile_type);
create index if not exists memory_embeddings_user_ns_idx on public.memory_embeddings(user_id, namespace);
create index if not exists memory_embeddings_source_idx on public.memory_embeddings(source_table, source_id);
create index if not exists memory_embeddings_vector_idx on public.memory_embeddings using ivfflat (embedding vector_cosine_ops) with (lists = 100);
create index if not exists memory_session_digests_user_ns_idx on public.memory_session_digests(user_id, namespace, created_at desc);
create index if not exists memory_open_loops_user_ns_idx on public.memory_open_loops(user_id, namespace, status);
alter table public.memory_capture_candidates enable row level security; alter table public.memory_profiles enable row level security; alter table public.memory_embeddings enable row level security; alter table public.memory_session_digests enable row level security; alter table public.memory_open_loops enable row level security; alter table public.memory_retrieval_logs enable row level security; alter table public.memory_model_call_logs enable row level security;
do $$ begin
  create policy "memory_capture_candidates_user_scoped" on public.memory_capture_candidates for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
  create policy "memory_profiles_user_scoped" on public.memory_profiles for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
  create policy "memory_embeddings_user_scoped" on public.memory_embeddings for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
  create policy "memory_session_digests_user_scoped" on public.memory_session_digests for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
  create policy "memory_open_loops_user_scoped" on public.memory_open_loops for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
exception when duplicate_object then null; end $$;
